INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Automated data extraction$q$, $q$OCR and machine learning read receipts, invoices, and bank statements to extract supplier, date, and amount data automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Accounting software integrations$q$, $q$Publishes extracted data directly into Xero, QuickBooks Online, Sage, and FreeAgent.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Mobile capture apps$q$, $q$iOS and Android apps let clients photograph receipts on the go for instant processing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Email forwarding inbox$q$, $q$Each user gets a unique email address to forward invoices and receipts for automatic capture.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Dext Commerce$q$, $q$Automatically imports sales, fees, and payout data from e-commerce and payment platforms like Amazon, Shopify, and Stripe.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Client portal$q$, $q$A dedicated portal lets accounting firm clients upload documents directly into the firm's workflow.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Dext Precision$q$, $q$Practice-management monitoring that tracks bookkeeping quality and data health across a firm's client roster.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$API access$q$, $q$Exposes an API for firms and software vendors to build custom integrations into the extraction pipeline.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$High-accuracy automated data extraction saves significant manual entry time$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Broad integration coverage with leading cloud accounting platforms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Simple mobile and email capture flow that non-technical clients can use easily$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Purpose-built for the accountant/bookkeeper workflow rather than generic expense tracking$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Pricing scales quickly for firms with many clients or high document volumes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Occasional extraction errors on low-quality or handwritten receipts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Learning curve when configuring supplier rules and chart-of-account mappings$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$No permanent free tier, only a time-limited free trial$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$What is Dext used for?$q$, $q$Dext automates the capture and data extraction of receipts, invoices, and bank statements so accountants and small businesses can avoid manual bookkeeping data entry.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$How much does Dext cost?$q$, $q$Dext's Business plan starts around $31.50/month (about $25.21/month billed annually) for 5 users and 250 documents, while the Practice plan for accounting firms starts around $239/month for 10 clients.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Does Dext have a free plan?$q$, $q$Dext does not offer a permanent free plan, but it does offer a free trial on both its Business and Practice plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Which accounting software does Dext integrate with?$q$, $q$Dext integrates with major cloud accounting platforms including Xero, QuickBooks Online, Sage, and FreeAgent.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Who owns Dext?$q$, $q$Dext was acquired by IRIS Software Group, a UK-based accounting and compliance software company, in December 2024.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Is Dext the same as Receipt Bank?$q$, $q$Yes, Dext was originally launched as Receipt Bank in 2010 and rebranded to Dext in 2021.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Accounting firm write-up work$q$, $q$Firms use Dext Practice to collect, extract, and code documents across dozens or hundreds of clients, speeding up monthly bookkeeping.$q$, $q$Accounting and bookkeeping firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Small business receipt management$q$, $q$Business owners photograph and forward receipts on the go, with Dext extracting and publishing the data into their accounting software.$q$, $q$Small and mid-sized businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$E-commerce seller bookkeeping$q$, $q$Dext Commerce automatically imports sales and fee data from marketplaces and payment processors for online sellers.$q$, $q$E-commerce businesses and their bookkeepers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Business$q$, $q$$31.50/month (~$25.21/month billed annually)$q$, $q$Monthly or Annual$q$, NULL, $q$["5 users","250 documents/month","Bank and accounting integrations","Mobile capture app"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Practice$q$, $q$From $239/month$q$, $q$Monthly or Annual$q$, NULL, $q$["10 business clients included","Client portal","Dext Precision practice monitoring","Per-client scaling for larger firms"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$Free Trial$q$, $q$Free$q$, $q$Time-limited$q$, NULL, $q$["Full feature access for evaluation period"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dext is a cloud bookkeeping automation platform that eliminates manual data entry by extracting information from receipts, invoices, bank statements, and e-commerce sales data, then publishing it directly into accounting software.$q$, $q$Originally launched as Receipt Bank in 2010 and rebranded to Dext in 2021, the London-based company serves both accounting firms managing many clients and individual small businesses managing their own books.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dext's OCR and machine-learning extraction engine reads photographed or scanned documents and identifies suppliers, line items, dates, and totals with claimed accuracy above 99 percent.$q$, $q$Add-on modules like Dext Commerce pull sales and fee data automatically from platforms such as Amazon, Shopify, and Stripe, while Dext Precision gives firms visibility into bookkeeping quality across their whole client base.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dext is priced by user count and monthly document volume across two plan families: Business, for companies managing their own books, and Practice, for accounting firms managing multiple clients.$q$, $q$Business plans start around $31.50/month (about $25.21/month billed annually), while Practice plans start around $239/month for ten business clients; a free trial is available and custom pricing exists for high-volume needs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6e9e3b9-7b4b-4224-9ce1-e8b76bd4f3c6', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Native distribution and sharding$q$, $q$Automatically shards and replicates data across a cluster for horizontal scalability and fault tolerance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$GraphQL-native querying$q$, $q$Supports GraphQL as a first-class query interface directly against the database, without a translation layer.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$DQL query language$q$, $q$Offers its own Dgraph Query Language for complex graph traversals beyond what GraphQL alone can express.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Open-source self-hosting$q$, $q$The core database can be downloaded and self-hosted for free under an open-source license.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Dgraph Cloud managed hosting$q$, $q$A fully managed cloud service with free, shared, and dedicated tiers removes operational overhead.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$ACID transactions$q$, $q$Supports distributed ACID-compliant transactions across the cluster for data consistency.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Go-based architecture$q$, $q$Built in Go for performance and concurrency, with Docker images used over ten million times.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Enterprise security add-ons$q$, $q$Dgraph Enterprise adds access control, security, and dedicated support for self-managed deployments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Free and open-source core with no licensing cost for self-hosting$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Natively distributed architecture scales linearly with added nodes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$First-class GraphQL support simplifies application development$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Strong open-source community with an active GitHub project$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Ownership changes (Hypermode acquisition in 2023, Istari Digital in 2025) create uncertainty about long-term commercial roadmap$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Smaller ecosystem and talent pool compared to Neo4j$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Managed Cloud pricing can add up for high-data-transfer workloads$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Steeper learning curve for teams unfamiliar with graph query languages$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Is Dgraph free to use?$q$, $q$Yes, the core Dgraph database is free and open-source to self-host; paid tiers only apply to the managed Dgraph Cloud service or enterprise add-ons.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$What query languages does Dgraph support?$q$, $q$Dgraph supports GraphQL natively as well as its own query language called DQL (Dgraph Query Language).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Who created Dgraph?$q$, $q$Dgraph was created in 2015 by Manish Rai Jain, a former Google engineer, through the company Dgraph Labs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$How much does Dgraph Cloud cost?$q$, $q$Dgraph Cloud offers a free tier, a Shared tier around $39.99/month per backend, and a Dedicated tier starting around $199/month.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Who owns Dgraph now?$q$, $q$Dgraph Labs was acquired by Hypermode in 2023, and the combined company was acquired by Istari Digital in October 2025.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$What is Dgraph used for?$q$, $q$Dgraph is used for applications with highly connected data such as social graphs, recommendation engines, knowledge graphs, and fraud detection systems.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Knowledge graph applications$q$, $q$Teams model deeply interconnected entities and relationships that are cumbersome to query with SQL joins.$q$, $q$Backend and data engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Recommendation and social graph systems$q$, $q$Applications that need fast traversal of user, content, and interaction relationships use Dgraph for low-latency graph queries.$q$, $q$Product engineering teams at consumer and social platforms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Managed graph database hosting$q$, $q$Teams that want graph database capability without operating infrastructure use Dgraph Cloud's shared or dedicated tiers.$q$, $q$Startups and small engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Open Source (self-hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full core database","Self-managed deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Dgraph Cloud Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Shared infrastructure","Limited data transfer","Good for prototyping"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Dgraph Cloud Shared$q$, $q$$39.99/month per backend$q$, $q$Monthly$q$, NULL, $q$["5GB data transfer included","$2/GB additional transfer","No storage or query fees"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$Dgraph Cloud Dedicated$q$, $q$From $199/month$q$, $q$Monthly$q$, NULL, $q$["Dedicated multi-AZ cluster","Available on AWS, GCP, Azure","Higher performance guarantees"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dgraph is an open-source, natively distributed graph database built in Go, designed for low-latency queries over highly connected data using either GraphQL or its native DQL query language.$q$, $q$Founded in 2015 by ex-Google engineer Manish Rai Jain, Dgraph became one of the most-starred graph databases on GitHub, and is now maintained under Istari Digital following acquisitions by Hypermode in 2023 and Istari in 2025.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dgraph shards and replicates data automatically across a cluster, scaling storage and query throughput roughly linearly as nodes are added, unlike single-node graph databases.$q$, $q$It supports GraphQL as a first-class API alongside its own DQL query language, letting developers query a graph directly without a separate GraphQL translation layer.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Dgraph database is free and open-source to self-host with no licensing fees.$q$, $q$Dgraph Cloud offers a free-forever tier, a Shared tier around $39.99/month per backend, and a Dedicated tier starting around $199/month for isolated multi-availability-zone clusters on AWS, GCP, or Azure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ed38eac2-96a6-4a42-b699-28e0cef88f69', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$No-login browser editor$q$, $q$Full diagramming functionality at app.diagrams.net without creating an account or signing in.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Cross-platform desktop app$q$, $q$Electron-based desktop application for Windows, macOS, and Linux for fully offline diagramming.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Extensive shape libraries$q$, $q$Thousands of built-in shapes covering flowcharts, UML, network topology, cloud architecture, and BPMN.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Cloud storage integrations$q$, $q$Native integration with Google Drive, Dropbox, OneDrive, GitHub, and GitLab for saving and syncing diagrams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Real-time collaboration$q$, $q$Multiple users can co-edit the same diagram simultaneously when stored in a connected cloud location.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Confluence and Jira embedding$q$, $q$Native apps let teams embed and edit diagrams directly inside Atlassian Confluence pages and Jira issues.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Client-side architecture$q$, $q$Diagrams are processed locally in the browser rather than sent to a remote server by default, aiding security-sensitive use.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Apache 2.0 licensed core$q$, $q$The underlying source code is open and self-hostable, enabling on-premise deployments for compliance needs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Completely free for individuals and teams with no feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$No account or login required to start diagramming$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Extremely broad shape library covering technical and business diagram types$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Open-source and self-hostable for security-sensitive organizations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Interface feels less polished than premium competitors like Lucidchart$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Real-time collaboration depends on which cloud storage backend is connected$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Enterprise support and SLAs require custom, quote-based pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Confluence/Jira integration costs scale with user count for larger teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Is diagrams.net the same as draw.io?$q$, $q$Yes, diagrams.net is the current primary brand name for the tool long known as draw.io; both names are used interchangeably and the software is identical.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Is diagrams.net really free?$q$, $q$Yes, the core web and desktop applications are completely free with no feature limits; the company monetizes through optional paid Confluence/Jira Marketplace apps and custom Enterprise support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Do I need an account to use diagrams.net?$q$, $q$No, you can use the full editor at app.diagrams.net without signing up, and optionally connect a cloud storage account like Google Drive to save files.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Is diagrams.net open source?$q$, $q$Yes, the core editor is released under the Apache 2.0 license and the source code is available on GitHub under jgraph/drawio.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Can diagrams.net be used offline?$q$, $q$Yes, a desktop app for Windows, macOS, and Linux allows fully offline diagram creation and editing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$What is diagrams.net used for?$q$, $q$It's used to create flowcharts, UML diagrams, network diagrams, floor plans, org charts, mind maps, and cloud architecture diagrams.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Software architecture documentation$q$, $q$Engineers diagram system architecture, network topology, and cloud infrastructure using dedicated AWS, Azure, and GCP shape libraries.$q$, $q$Software engineers and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Business process mapping$q$, $q$Teams document workflows and BPMN business processes using drag-and-drop flowchart shapes.$q$, $q$Business analysts and operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Embedded wiki diagrams$q$, $q$Organizations embed diagrams.net directly inside Confluence, Notion, or self-hosted wikis for living documentation.$q$, $q$Technical writers and knowledge-management teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Free (Web & Desktop)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited diagrams","All diagram types and shape libraries","Cloud storage integrations","No account required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Confluence/Jira Cloud App$q$, $q$From ~$1.70/user/month$q$, $q$Monthly$q$, NULL, $q$["Embedded diagram editing in Confluence and Jira","Sliding per-user pricing that decreases at scale"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$Enterprise$q$, $q$Custom$q$, $q$Annual (quote-based)$q$, NULL, $q$["Dedicated support","Data-center deployment options","Compliance and security assistance"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Diagrams.net, better known by its long-running name draw.io, is a free, open-source diagramming application for flowcharts, UML, network diagrams, and more, usable in-browser or offline with no account required.$q$, $q$Its technology traces back to the JGraph library started in 2000 by Gaudenz Alder, evolving through Diagramly and draw.io before the product settled on the diagrams.net brand in 2020.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The editor offers a drag-and-drop canvas with thousands of shapes covering flowcharts, network diagrams, UML, cloud architecture icons, and more, plus real-time collaborative editing.$q$, $q$It runs entirely client-side in the browser or as a cross-platform desktop app, and integrates with Google Drive, Dropbox, OneDrive, GitHub, Confluence, Jira, and Notion.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core diagrams.net application is completely free to use, with no login required and no artificial feature limits for individuals or teams.$q$, $q$Revenue comes mainly from paid Confluence/Jira Marketplace app listings priced per user per month, plus custom Enterprise pricing for large organizations needing dedicated support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
