INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('af654930-837f-40c8-b359-6e2d826ad6ff', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$AI-powered call transcription$q$, $q$Real-time transcription of every call and meeting using Dialpad's proprietary DialpadGPT model.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Live sentiment analysis$q$, $q$Detects customer sentiment during live calls to help agents and managers respond appropriately.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Automatic call summaries and action items$q$, $q$AI generates post-call summaries and extracts action items without manual note-taking.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Real-time agent coaching$q$, $q$AI-powered coaching prompts assist sales and support agents live during customer interactions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Cloud VoIP business phone system$q$, $q$Unlimited calling, call routing, voicemail transcription, and virtual office locations without on-premise PBX hardware.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$AI Contact Center$q$, $q$Automated quality management and AI assist features tailored to customer support and sales teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Video meetings with AI notes$q$, $q$Dialpad Ai Meetings offers video conferencing with AI-generated meeting notes and action items.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$CRM integrations$q$, $q$Native integrations with Salesforce, HubSpot, Zendesk, and other CRM platforms.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Deep, proprietary AI features (transcription, coaching, sentiment) built directly into the platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Fully cloud-based with native apps across desktop and mobile, ideal for remote teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Unified platform covering phone, meetings, and contact center in one system$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Backed by significant funding and Google Cloud infrastructure for reliability$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Advanced AI and higher-tier plans increase cost relative to bare-bones VoIP competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Call quality depends on the customer's own internet connection since there's no dedicated telephony hardware$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Enterprise-grade features require custom quote-based pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Some features and pricing vary significantly across the separate Voice, Meetings, and Contact Center product lines$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$What is Dialpad used for?$q$, $q$Dialpad is used as a cloud business phone system, video meeting platform, and AI-powered contact center for customer support and sales teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$How much does Dialpad cost?$q$, $q$Dialpad Ai Voice starts around $15 per user per month billed annually (Standard tier), with a Pro tier around $25 per user per month annually and custom Enterprise pricing available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Who founded Dialpad?$q$, $q$Dialpad was founded in 2011 by Craig Walker, John Rector, and Brian Peterson, originally operating as Firespotter Labs before becoming UberConference and then Dialpad.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$What AI model does Dialpad use?$q$, $q$Dialpad uses its own proprietary large language model, DialpadGPT, built on Google Cloud infrastructure, to power transcription, summaries, and coaching.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Does Dialpad offer a free trial?$q$, $q$Yes, Dialpad offers a free trial for prospective customers to evaluate the platform before purchasing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Who are Dialpad's main competitors?$q$, $q$Dialpad competes with RingCentral, 8x8, Nextiva, Vonage, Zoom Phone, and Five9 in the cloud business communications market.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Cloud business phone replacement$q$, $q$Companies replace legacy on-premise PBX systems with Dialpad's cloud VoIP service for distributed and remote teams.$q$, $q$Small and mid-sized businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$AI-enhanced customer support$q$, $q$Contact centers use Dialpad Ai Contact Center for automated quality management, live sentiment analysis, and agent coaching.$q$, $q$Customer support and contact center teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Sales call intelligence$q$, $q$Sales teams use Dialpad Ai Sales for real-time coaching and deal intelligence pulled automatically from call transcripts.$q$, $q$Sales teams and RevOps$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Standard (Ai Voice)$q$, $q$$15/user/month annual ($23/month month-to-month)$q$, $q$Monthly or Annual$q$, NULL, $q$["Unlimited calling","Voicemail transcription","AI call summaries","One office location"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Pro (Ai Voice)$q$, $q$$25/user/month annual ($35/month month-to-month)$q$, $q$Monthly or Annual$q$, NULL, $q$["Multiple office locations","CRM integrations","Advanced call routing","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$Enterprise$q$, $q$Custom$q$, $q$Annual (quote-based)$q$, NULL, $q$["99.99% uptime SLA","Advanced security and compliance","Unlimited office locations","Dedicated account management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dialpad is a cloud-based business communications platform unifying AI-powered phone calling, video meetings, messaging, and contact center software into one system.$q$, $q$Founded in 2011 by Craig Walker (formerly of Google Voice), John Rector, and Brian Peterson, the San Ramon, California company has raised roughly $476 million and reached a $2.2 billion valuation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dialpad runs on Google Cloud and uses its own proprietary DialpadGPT model to power real-time transcription, live sentiment analysis, automatic call summaries, and agent coaching.$q$, $q$The product line spans Dialpad Ai Voice for business phone service, Ai Meetings for video conferencing, and Ai Contact Center for AI-enhanced customer support and sales.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dialpad Ai Voice starts around $15/user/month billed annually (Standard tier) or $23/month billed monthly, with a Pro tier around $25/user/month annually.$q$, $q$An Enterprise tier is available at custom pricing for large organizations, and each product line (Meetings, Contact Center, Sales) has its own separate tiered pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
