INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d765235-7add-4917-a93e-2e11d8fe95a8', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Federated pod network$q$, $q$Independently run servers called pods interoperate so users on different pods can still follow and interact with each other.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Aspects-based privacy control$q$, $q$Users group contacts into Aspects and choose exactly which group sees each individual post.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$No advertising or data harvesting$q$, $q$The platform has no ad-targeting business model and does not sell or exploit user data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Reverse-chronological feed$q$, $q$Posts appear in chronological order rather than through an engagement-optimized algorithm.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Open-source, self-hostable software$q$, $q$Anyone can run their own pod using the publicly available Ruby on Rails codebase.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Cross-pod interaction$q$, $q$Users can follow, message, and interact with accounts on entirely different pods, similar to federated email.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$API access for third-party clients$q$, $q$Since version 0.9.0.0, an API layer supports third-party and mobile client applications.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Democratic governance$q$, $q$Project decisions are made transparently through community voting on the Loomio platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Completely free with no ads, tracking, or data-harvesting business model$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Decentralized architecture means no single company can shut down or control the network$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Granular Aspects-based privacy controls exceed typical public/private toggles$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Fully open-source, allowing anyone to audit, self-host, or modify the software$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Smaller, less active user base compared to mainstream social networks$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Choosing and trusting a pod adds friction compared to signing up for a single centralized service$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Slower feature development pace as a volunteer-run, non-commercial project$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Network effects favor larger platforms, limiting mainstream discovery and growth$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$What is diaspora*?$q$, $q$diaspora* is a free, open-source, decentralized social network made up of independently run servers called pods that let users interact across the whole network.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Is diaspora* free to use?$q$, $q$Yes, diaspora* is entirely free, with no subscription plans, advertising, or premium tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Who created diaspora*?$q$, $q$diaspora* was founded in 2010 by four NYU students: Ilya Zhitomirskiy, Dan Grippi, Max Salzberg, and Raphael Sofaer, after a successful Kickstarter campaign.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$What is a 'pod' in diaspora*?$q$, $q$A pod is an independently owned and operated server running the diaspora* software; pods communicate with each other so users on different pods can still connect.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Who runs diaspora* today?$q$, $q$diaspora* is governed by the nonprofit diaspora* Foundation, part of the Free Software Support Network, using democratic community decision-making.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$How is diaspora* different from Facebook?$q$, $q$Unlike Facebook, diaspora* has no central owner, no advertising, no algorithmic feed, and gives users granular control over who sees each post via Aspects.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Privacy-focused social networking$q$, $q$Users who want to avoid advertising-driven, data-harvesting social platforms join or run a diaspora* pod.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Community and interest-based discussion$q$, $q$Groups interested in technology, activism, or specific niche topics run dedicated pods for focused community discussion.$q$, $q$Online communities and advocacy groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Self-hosted social infrastructure$q$, $q$Organizations or individuals run their own pod to have full control over their social networking infrastructure and data.$q$, $q$Self-hosting enthusiasts and small organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Join any public pod","Full access to posting, Aspects, and federation","Option to self-host your own pod"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$diaspora* is a free, open-source, decentralized social network made up of independently run servers called pods that interoperate so users can connect across the entire network regardless of which pod they join.$q$, $q$Founded in 2010 by four NYU students after a Kickstarter campaign raised over $200,000, the project is now governed by the nonprofit diaspora* Foundation rather than a corporation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$diaspora*'s 'Aspects' feature lets users group contacts and control exactly which group sees each post, offering more granular privacy than a simple public/private toggle.$q$, $q$The platform has no advertising, no algorithmic feed, and no data-harvesting business model, showing posts in reverse-chronological order instead.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8116962c-5001-43e3-b838-698a93f20293', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$diaspora* is entirely free to use; anyone can join an existing pod or run their own pod using the open-source, AGPL-3.0-licensed software.$q$, $q$There are no subscription tiers, premium features, or advertising-based monetization, consistent with its nonprofit, community-governed structure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8116962c-5001-43e3-b838-698a93f20293', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8116962c-5001-43e3-b838-698a93f20293', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8116962c-5001-43e3-b838-698a93f20293', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8116962c-5001-43e3-b838-698a93f20293', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8116962c-5001-43e3-b838-698a93f20293', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Visual workflow builder$q$, $q$Node-based canvas for chaining LLM calls, conditional logic, tool calls, and retrieval steps into production AI workflows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Retrieval-augmented generation (RAG)$q$, $q$Automatically chunks, embeds, and indexes private documents so LLM answers are grounded in an organization's own data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$AI agent framework$q$, $q$Supports tool-calling and multi-step reasoning loops for building autonomous AI agents.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Model-agnostic LLM support$q$, $q$Works with OpenAI, Anthropic, Google, Mistral, open-weight models, and self-hosted inference backends.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Prompt engineering IDE$q$, $q$A dedicated environment for developing, testing, and iterating on prompts and few-shot examples.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Self-hosted Community edition$q$, $q$The open-source core can be self-hosted for free indefinitely under the Dify Open Source License.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Observability and analytics$q$, $q$Built-in logging and monitoring tools track app usage, message volume, and performance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Enterprise governance$q$, $q$SSO, multiple workspaces, and advanced security controls available on the Enterprise tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Genuinely open-source and self-hostable core, avoiding vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Model-agnostic support across all major LLM providers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Integrated RAG and agent stack reduces the need to stitch together separate tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Accessible visual builder usable by both developers and less technical team members$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Cloud plan message-credit limits can be restrictive for high-volume production apps$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Open-source license includes restrictions on certain multi-tenant SaaS resale use cases$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Enterprise-grade governance features require custom, quote-based pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Younger company (founded 2023) with a smaller support ecosystem than established players like LangChain$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$What is Dify used for?$q$, $q$Dify is used to build LLM-powered applications such as chatbots, RAG knowledge assistants, and multi-step AI agents using a visual workflow builder.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Is Dify free?$q$, $q$Yes, Dify offers a free Sandbox cloud tier and a free, open-source Community edition that can be self-hosted indefinitely; paid Professional, Team, and Enterprise tiers unlock higher limits and support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Who created Dify?$q$, $q$Dify is developed by LangGenius, Inc., founded in 2023 by Luyu Zhang and John Wang, headquartered in Sunnyvale, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Is Dify open source?$q$, $q$Yes, Dify's core is open-source on GitHub under a license based on Apache 2.0 with added conditions restricting certain multi-tenant SaaS resale without a commercial agreement.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Which LLM providers does Dify support?$q$, $q$Dify is model-agnostic and supports OpenAI, Anthropic, Google, Mistral, open-weight models, and self-hosted inference backends.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$How much does Dify Cloud cost?$q$, $q$Dify Cloud's Professional plan is around $59/month and the Team plan is around $159/month, in addition to a free Sandbox tier and custom Enterprise pricing.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Internal knowledge-base chatbots$q$, $q$Teams build RAG-based assistants that answer questions grounded in private company documents.$q$, $q$Internal platform and data teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Customer support automation$q$, $q$Companies build AI agents and chatbots that handle customer inquiries using Dify's workflow builder.$q$, $q$Customer support and product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$AI SaaS product development$q$, $q$Independent developers and startups build and ship AI-powered SaaS products on top of Dify's orchestration layer.$q$, $q$Independent developers and startups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Sandbox$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["200 message credits","1 workspace","1 team member","5 apps","50 knowledge documents"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Professional$q$, $q$$59/month (~$590/year annual)$q$, $q$Monthly or Annual$q$, NULL, $q$["5,000 monthly message credits","3 team members","50 apps","No API rate limits"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Team$q$, $q$$159/month (~$1,590/year annual)$q$, $q$Monthly or Annual$q$, NULL, $q$["10,000 monthly message credits","50 team members","200 apps","20GB storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Community (self-hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source core features","Self-managed deployment","Single workspace"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$Enterprise$q$, $q$Custom$q$, $q$Annual (quote-based)$q$, NULL, $q$["Multiple workspaces","SSO","Commercial license","Dedicated support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dify is an open-source LLM application development platform that combines a visual workflow builder, RAG pipeline, AI agent framework, and model management in one self-hostable or cloud-hosted system.$q$, $q$Built by LangGenius, Inc., founded in 2023 by Luyu Zhang and John Wang in Sunnyvale, California, Dify has raised roughly $30 million in Series Pre-A funding led by HSG.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$A node-based visual workflow builder lets developers chain LLM calls, conditional logic, code execution, API calls, and retrieval steps without hand-building orchestration plumbing.$q$, $q$Its RAG pipeline automatically chunks, embeds, and indexes private documents so LLM responses can be grounded in an organization's own data, and the platform is model-agnostic across major LLM providers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dify Cloud offers a free Sandbox tier, a Professional plan around $59/month, and a Team plan around $159/month, each with rising message-credit, app, and storage limits.$q$, $q$The Community edition is free and open-source to self-host indefinitely, and an Enterprise tier offers custom pricing with SSO, advanced security, and dedicated support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
