INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d515660a-2710-4138-a906-19ab0c3f0a81', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Real-time collaborative editing$q$, $q$Multiple users can simultaneously edit the same whiteboard from computers, tablets, or smartphones.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$No-account access$q$, $q$Boards can typically be created and joined without requiring a personal user account, minimizing data collection.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Integrated image search$q$, $q$Built-in Pixabay API integration lets users search and add images directly to a board.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Configurable file uploads$q$, $q$Administrators can configure upload size limits for files added to boards.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Session duration controls$q$, $q$Configurable session settings determine how long a board remains active and editable.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Self-hosting support$q$, $q$Open-source code can be deployed locally via npm, PM2, or Docker for institutions needing full data control.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$AGPLv3 open-source license$q$, $q$Fully open source code published on Codeberg, ensuring transparency and preventing proprietary lock-in.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Embedded content support$q$, $q$Boards can display embedded content from authorized external domains.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Completely free with no account or payment required to use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Privacy-respecting design suited to schools with strict student-data regulations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Open-source and self-hostable for institutions needing full data control$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Simple, lightweight interface focused specifically on classroom and team collaboration$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Fewer advanced features than commercial whiteboard tools like Miro$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Small, largely one-person-led team means slower feature development pace$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Primarily French-language community and documentation, though English and Italian are supported$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Relies on donation-based funding rather than a dedicated support/SLA structure$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Is Digiboard free?$q$, $q$Yes, Digiboard is completely free to use, with no subscription tiers or paid features, funded through voluntary donations to La Digitale.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Who created Digiboard?$q$, $q$Digiboard is part of La Digitale, an educational technology project created by French developer Emmanuel Zimmert, launched in 2020.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Do I need an account to use Digiboard?$q$, $q$No, Digiboard is designed so boards can generally be created and joined without a personal account, minimizing data collection.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Is Digiboard open source?$q$, $q$Yes, Digiboard's source code is published on Codeberg under the GNU AGPLv3 license.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Can Digiboard be self-hosted?$q$, $q$Yes, institutions can self-host their own instance using npm, PM2, or Docker for full control over data storage.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$What is Digiboard used for?$q$, $q$Digiboard is used to create real-time collaborative whiteboards for classroom activities, brainstorming, and remote team collaboration.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Classroom collaborative activities$q$, $q$Teachers create live whiteboards where students post ideas, answers, or brainstorm content in real time.$q$, $q$K-12 and higher-education teachers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Remote meeting facilitation$q$, $q$Teams use Digiboard as a free, privacy-respecting alternative to commercial whiteboard tools for remote brainstorming.$q$, $q$Small teams and organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Self-hosted institutional deployment$q$, $q$Schools and IT departments deploy their own Digiboard instance to keep student data fully under institutional control.$q$, $q$School IT administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited board creation","Real-time collaboration","No account required","Self-hosting option available"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Digiboard is a free, open-source collaborative whiteboard from La Digitale, a French educational technology project created by Emmanuel Zimmert and launched in 2020.$q$, $q$It lets teachers, trainers, and teams create real-time shared boards that multiple participants can edit simultaneously from computers, tablets, or phones, without needing to create an account.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Digiboard supports real-time multi-user collaboration, configurable file uploads, and integrated Pixabay image search, built on Vue.js, Node.js, Express, and Redis.$q$, $q$The full source code is published under the AGPLv3 license on Codeberg, allowing schools and organizations to self-host their own instance for full data control.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Digiboard is completely free with no subscription tiers or paid feature gates, funded through voluntary donations to La Digitale rather than commercial sales.$q$, $q$Its AGPLv3 open-source license also allows free self-hosting for institutions that want full control over where board data is stored.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
