INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('49e87fbd-548a-4c83-b5b3-b84d439ae13c', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Curated link bundles$q$, $q$Organizes external web links with a title, description, and color code into one clean, shareable page.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$No-login sharing$q$, $q$Shared link bundles can typically be viewed and accessed without requiring an account.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Multi-language support$q$, $q$Interface and translation strings support French, English, Italian, Spanish, and more.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Privacy-respecting analytics$q$, $q$Built-in support for Umami, an open-source, cookie-free traffic analytics alternative to Google Analytics.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Flexible database backends$q$, $q$Uses SQLite by default with MariaDB or MySQL available for larger self-hosted deployments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Domain-based API security$q$, $q$Restricts which external domains can be called through the API as an abuse safeguard.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Self-hosting support$q$, $q$Open PHP-based source code allows schools and organizations to self-host their own instance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$AGPLv3 open-source license$q$, $q$Fully open source code published on Codeberg, ensuring transparency and preventing proprietary lock-in.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Completely free with no account or payment required to use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Simple, purpose-built design for educational link curation rather than social media profiles$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Open-source and self-hostable for institutions needing full data control$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Supports gamified use cases like treasure-hunt style learning activities$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Fewer customization and design options than commercial link-in-bio tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Small, largely one-person-led team means slower feature development pace$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Primarily French-language community and documentation despite multi-language support$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Relies on donation-based funding rather than a dedicated support/SLA structure$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Is Digibunch free?$q$, $q$Yes, Digibunch is completely free to use, with no subscription tiers or paid features, funded through voluntary donations to La Digitale.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Who created Digibunch?$q$, $q$Digibunch is part of La Digitale, an educational technology project created by French developer Emmanuel Zimmert, launched in 2020.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$What is Digibunch used for?$q$, $q$Digibunch is used to bundle curated collections of web links, each with a title and description, into a single clean shareable page for students or colleagues.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Is Digibunch open source?$q$, $q$Yes, Digibunch's source code is published on Codeberg under the GNU AGPLv3 license.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Can Digibunch be self-hosted?$q$, $q$Yes, since it is built with PHP and supports SQLite, MariaDB, or MySQL, schools and organizations can self-host their own instance.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$How is Digibunch different from Linktree?$q$, $q$Digibunch is purpose-built for educational resource curation rather than social-media profile links, letting each link include a title, description, and color code.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Curated learning paths$q$, $q$Teachers combine multiple online resources in a defined order to guide students through a lesson or unit.$q$, $q$K-12 and higher-education teachers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Thematic bibliographies and sitographies$q$, $q$Educators and librarians compile and share curated reference link collections with colleagues or students.$q$, $q$School librarians and researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Gamified treasure hunt activities$q$, $q$Creators build a chain of linked pages each containing clues or riddles that lead to the next step.$q$, $q$Primary and secondary school teachers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited link bundles","Custom titles, descriptions, and color codes","No account required","Self-hosting option available"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Digibunch is a free, open-source link-bundling tool from La Digitale, a French educational technology project founded by Emmanuel Zimmert and launched in 2020.$q$, $q$It lets teachers and curators organize collections of external web links, each with a title, description, and color code, into a single clean shareable webpage.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Digibunch is built with a Vue.js frontend and PHP backend, supporting SQLite by default with MariaDB or MySQL as alternatives, plus privacy-respecting Umami analytics.$q$, $q$The source code is published under the AGPLv3 license on Codeberg, letting schools self-host their own instance for full control over data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8d19f4f-f413-441c-b903-3a6fd99103e0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Digibunch is entirely free with no subscription plans or paid feature gates, sustained through voluntary donations to La Digitale.$q$, $q$Its open-source AGPLv3 license also allows free self-hosting for institutions with PHP hosting capability.$q$]::text[], 2);
